+impl AgentRecord {
+    fn materials(&self) -> impl Iterator<Item = &Handle<StandardMaterial>> {
+        let mut handles: Vec<&Handle<StandardMaterial>> = Vec::new();
+        let mut push_part = |part: &PartRef, store: &mut Vec<&Handle<StandardMaterial>>| {
